export function quote(input: any): unknown {
  const runeCount = input.items.filter((item: any) => item.type === "rune").length;
  const isRuneBlock = runeCount === 3;
  const itemsBase = isRuneBlock
    ? 60
    : input.items.reduce(
        (sum: number, item: any) => sum + (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0),
        0
      );
  return { premium: itemsBase + PROCESSING_FEE };
}
